/* style.css */
body {
  margin: 0;
  font-family: system-ui, sans-serif;
  background: #0f172a;
  color: #e2e8f0;
}

nav {
  display: flex;            /* puts the links in a ROW      */
  justify-content: center;
  gap: 16px;
  padding: 16px;
}

main {
  display: flex;            /* puts the cards in a ROW too  */
  gap: 16px;
  flex-wrap: wrap;
  padding: 16px;
}

